// const dom = require("../templates/Label.ejs");
import { Control } from './Control';
import { ControlEditor } from '../../editor/ControlEditor';
import { express } from '../../core/express';


import { map } from '../../decorator/controlmap';

@map('文本基类', 'dsf.text', 'Text')
export class Text extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$value = "文本";
    this.defaultValue = null;
  }

  get value() {
    if (!this.$value && this.defaultValue) {
      let exp = dsf.Express;
      this.$value = exp.replace(this.defaultValue.text);
    }
    return this.$value;
  }

  set value(value) {
    this.$value = value;
  }

}