import dom from '../templates/QsCheckBox.ejs';
import { isSupportDataPost } from '../../../core/postDecorator';
import { QsItemsMetaData } from '../../../core/metadata';
import { FormControlEvent } from '../../../core/ControlEvent';

import { controlBaseSetting } from '../../../decorator/controlBaseSetting';
import {map} from  '../../../decorator/controlmap';

@map('多选题','dsf.qi.checkbox','QsCheckBox')
@controlBaseSetting("QSCheckBox2.html", "多选题", null, null)
@isSupportDataPost(true)
export class QsCheckBox extends dsf.Controls.Question {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$isOther = false;

        this.$metadata = QsItemsMetaData.call(this);
        this.$validateCode = this.$metadata.validate.code;

        //题干
        this.$questionBody = "";
        //值
        this.$value = [];

        this.colNum = 0;
        this.$mustCheckNum = 0;
        this.$maxCheckNum = 0;
        this.$minCheckNum = 0;
        this._items = [];
        this._itemsBox = null;
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this.renderContext();
        }
    }

    get value() {
        let _this = this;
        if (!_this.$value) {
            _this.$value = [];
        }
        _this.$value.forEach(function (o, i) {
            if (o.value == "else") {
                if (_this._itemsBox) {
                    o.attach_text = _this._itemsBox.find("div.q_other>input").val();
                }
            } else {
                o.attach_text = "";
            }
        });
        return _this.$value;
    }

    set value(value) {
        setValue.call(this, value, true);
    }

    set isOther(value) {
        this.$isOther = value;
        if (this.element) {
            this.renderContext();
        }
    }
    get isOther() {
        return this.$isOther;
    }

    get mustCheckNum() {
        return this.$mustCheckNum;
    }
    set mustCheckNum(val) {
        if (isNaN(val)) {
            layer.msg("只能输入数字", { icon: 5 });
            return
        }
        if (+val > this._items.length) {
            layer.msg("限选择数不能大于选项数", { icon: 5 });
            return
        }
        this.$mustCheckNum = +val;
    }

    get maxCheckNum() {
        return this.$maxCheckNum;
    }
    set maxCheckNum(val) {
        if (isNaN(val)) {
            layer.msg("只能输入数字", { icon: 5 });
            return
        }
        if (+val > this._items.length) {
            layer.msg("最大选择数不能大于选项数", { icon: 5 });
            return
        }
        this.$maxCheckNum = +val;
    }

    get minCheckNum() {
        return this.$minCheckNum;
    }
    set minCheckNum(val) {
        if (isNaN(val)) {
            layer.msg("只能输入数字", { icon: 5 });
            return
        }
        if (+val<0) {
            layer.msg("最小选择数不能小于0", { icon: 5 });
            return
        }
        this.$minCheckNum = +val;
    }

    set staticItem(val) {
        this.$metadata.dataSource = val;
    }

    get items() {
        return this._items;
    }
    set items(value) {
        this._items = [];
        for (let i = 0; i < value.length; i++) {
            let isRender = i == value.length - 1 ? true : false;
            this.addItem(value[i], i, isRender);
        }
        if (this._items.length <= 0) {
            this.renderItems();
        }
    }

    initTemplate() {
        return dom(this);
    }
    createElement() {
        super.createElement();
        this._itemsBox = this._handlers.content;
    }

    renderContext() {
        if (this.$required) {
            this.$metadata.validate.code = this.$validateCode;
        } else {
            this.$metadata.validate.code = null;
        }
        super.renderContext();
        this._handlers.questionBody && this._handlers.questionBody.html(this.$questionBody);
        // this._handlers.checkNum && this._handlers.checkNum.html();
        if (this.root && this.root._isDesign && this.$metadata.dataSource) {
            if (this.$metadata.dataSource.type == 'vcode') {
                this.items = [];
            } else if (this.$metadata.dataSource.type == 'static') {
                this.items = this.$metadata.dataSource.code || [];
            }
        }
        if (this._itemsBox) {
            this.renderItems();
        }
    }

    renderReady() {
        let _this = this;
        super.renderReady();
        // dsf.UI.render("checkbox", true,null, 'checkbox_' + _this.id);
        layui.form.on('checkbox(' + this.id + ')', function (data) {
            let checked = _this.element.find("input:checked");
            if(!!_this.mustCheckNum&& data.elem.checked){
                if (checked.length > _this.mustCheckNum * 1) {
                    data.elem.checked = false;
                    data.othis.removeClass('layui-form-checked');
                    dsf.layer.message("限选" + _this.mustCheckNum + "个", false);
                    return;
                }
            }else{
                if (!!_this.maxCheckNum && data.elem.checked) {
                    if (checked.length > _this.maxCheckNum * 1) {
                        data.elem.checked = false;
                        data.othis.removeClass('layui-form-checked');
                        dsf.layer.message("最多只能选择" + _this.maxCheckNum + "个", false);
                        return;
                    }
                }
            }

            let arr = [];
            checked.each((i, el) => {
                arr.push($(el).val());
            });
            setValue.call(_this, arr, false);
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
        });
    }
    renderItems() {
        if (this._itemsBox) {
            this._itemsBox.html("");
        }
        if (this.root._isDesign && this.items.length <= 0) {
            for (let i = 0; i < 2; i++) {
                let value = (i + 1);
                let name = this.name || this.id;
                let op = $("<input type='checkbox' lay-skin='primary' " + (this.readOnly ? "disabled" : "") + " lay-filter='" + this.id + "' title='选项" + value + "' name='" + (name) + "' value='" + value + "'/>");
                this._itemsBox.append(op);
            }
            if (this.isOther) {
                this._itemsBox.append("<input type='checkbox' lay-skin='primary' " + (this.readOnly ? "disabled" : "") + " lay-filter='" + this.id + "' title='其他' />");
            }
        } else {
            //判断items中是否已经存在其他如果没有则追加一个
            if (this.isOther) {
                let otherItem = null;
                let index = _.findIndex(this.items, { "value": "else" });
                if (index >= 0) {
                    otherItem = this.items[index];
                    this.items.splice(index, 1);
                }
                if (!otherItem) {
                    otherItem = {
                        "text": "其他",
                        "value": "else",
                        "attach_text": ""
                    }
                }
                this.items.push(otherItem);
            }
            for (let i = 0; i < this.items.length; i++) {
                let item = this.items[i];
                let name = this.name || this.id;
                if (item.attach_text == undefined) {
                    item.attach_text = "";
                }
                let checked = false;
                let val = $.isArray(this.value) ? this.value : [this.value];
                let result = _.find(val, { "value": val.value });
                if (checked) {
                    checked = true;
                }
                let op = $("<input type='checkbox' lay-skin='primary' " + (this.readOnly ? "disabled" : "") + " lay-filter='" + this.id + "' title='" + item.text + "' name='" + (name) + "' value='" + (item.value) + "' " + (checked ? "checked" : "") + "/>");
                this._itemsBox.append(op);
                if (item.value == "else") {
                    this._itemsBox.append('<div class="q_other"><input type="text"></div>');
                    if (this.value.value == "else") {
                        this._itemsBox.find(".q_other>input").val(result ? result.attach_text : "");
                    }
                }
            }
        }
        renderCheckbox.call(this)
    }
    initEvent() {
        let _this = this;
        this.element.on("input", ".q_other>input[type=text]", evt => {
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
        });
    }

    addItem(option, index, isRender) {
        if (index === undefined || index === null) {
            this.items.push(option);
        } else {
            this.items.splice(index, 0, option);
        }
        // this._itemDictionary[option.value] = option;
        if (isRender != false) {
            if (this._itemsBox) {
                this.renderItems();
            }
        }
    }

    getTextString() {
        if (this.$metadata.defaultValue) {
            return this.questionBody + this.$metadata.defaultValue.text;
        }
        return this.questionBody
    }

    createMetaData() {
        let m = super.createMetaData();
        if (m.md.dataSource) {
            this.isOther ? m.md.dataSource.attach = [{ "text": "其他", "value": "else" }] : m.md.dataSource.attach = [];
        }
        return m;
    }
}


//通过value字符串获取选项数据
function getItemByValueString(val) {
    let item = null;
    if (typeof (val) == "string") {
        item = _.find(this.items, { value: val });
    } else if (typeof (val) == "object") {
        item = _.find(this.items, { value: val.value });
    }
    return item;
}

//设置值
function setValue(val, flag) {
    var _this = this;
    var val = $.isArray(val) ? val : [val];
    this.$value = [];
    var currentCheckedArr = [];
    val.forEach(function (o, i) {
        let item = null;
        typeof (o) == "string" ? item = getItemByValueString.call(_this, o) : item = _.find(_this.items, { "value": o.value });
        if (item) {
            if (o.attach_text != undefined) {
                item.attach_text = o.attach_text;
            }
            currentCheckedArr.push(item);
        }
    })
    this.items.forEach(function (o, i) {
        let result = _.find(currentCheckedArr, { "value": o.value });
        let checkbox = _this._itemsBox.find("input[value='" + o.value + "']");
        if (result) {
            checkbox.prop("checked", true);
            _this.$value.push(result);
        } else {
            checkbox.prop("checked", false);
        }
        if (o.value == "else") {
            let attachInput = _this._itemsBox.find("div.q_other>input")
            attachInput.val(o['attach_text']);
        }
        checkedItem.call(_this, o);
    });
    renderCheckbox.call(this)
}

function checkedItem(item) {
    let elem = this._itemsBox.find("input[value='" + item.value + "']");
    if (elem.length > 0) {
        let data = {
            "elem": elem.get(0),
            "value": item.value
        }
        this.checkTrigHidden(data, this);
    }
}

function renderCheckbox() {
    if (isNaN(+this.colNum) || +this.colNum < 0 || +this.colNum > 10) {
        dsf.layer.message("请输入0~10之间的数字", false);
        dsf.UI.render("checkbox", true,null,'checkbox_' + this.id)
    } else {
        let _this = this;
        if(_this._isDesign){
            dsf.UI.render("checkbox", true, function () {
                var all = _this._itemsBox.find(".layui-form-checkbox");
                $(all).css("width", (100 / +_this.colNum).toFixed(2) + "%");
                if (_this.isOther) {
                    $(all).last().css("width", "auto");
                }
            }, 'checkbox_' + _this.id);
        }else{
            layui.form.render('checkbox','checkbox_' + _this.id);
            var all = _this._itemsBox.find(".layui-form-checkbox");
            $(all).css("width", (100 / +_this.colNum).toFixed(2) + "%");
            if (_this.isOther) {
                $(all).last().css("width", "auto");
            }
        }
    }
}
