import dom from '../templates/QsRadio.ejs';
import { isSupportDataPost } from '../../../core/postDecorator';
import { QsItemsMetaData } from '../../../core/metadata';
import { FormControlEvent } from '../../../core/ControlEvent';

import {controlBaseSetting} from "../../../decorator/controlBaseSetting";
import {map} from  '../../../decorator/controlmap';

@map('单选题','dsf.qi.radio','QsRadio')
@controlBaseSetting("QSRadio2.html","单选题",null,'530px')
@isSupportDataPost(true)
export class QsRadio extends dsf.Controls.Question {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$isOther = false;

        this.$metadata = QsItemsMetaData.call(this);
        this.$validateCode = this.$metadata.validate.code;
        //题干
        this.$questionBody = "";
        //值
        this.$value = "";

        this.colNum = 0;
        this._items = [];
        this._itemsBox = null;
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this.renderContext();
        }
    }

    get value() {
        //获取value属性时，如果选择了其他默认将附加文本添加到$value属性中
        if (this.$value == "") {
            this.$value = { "text": "", "value": "", "attach_text": "" };
        }
        if (this.$value.value == "else") {
            if (this._itemsBox) {
                this.$value['attach_text'] = this._itemsBox.find("div.q_other>input").val();
            }
        }
        return this.$value;
    }

    set value(val) {
        setValue.call(this, val, true);
    }

    set staticItem(val){
        this.$metadata.dataSource=val;
    }

    set isOther(value) {
        this.$isOther = value;
        if (this.element) {
            this.renderContext();
        }
    }
    get isOther() {
        return this.$isOther;
    }

    get items() {
        return this._items;
    }
    set items(value) {
        this._items = [];
        for (let i = 0; i < value.length; i++) {
            let isRender = i == value.length - 1 ? true : false;
            this.addItem(value[i], i, isRender);
        }
        if (this._items.length <= 0) {
            this.renderItems();
        }
    }

    initTemplate() {
        return dom(this);
    }

    initEvent(){
        let _this=this;
        this.element.on("input",".q_other>input[type=text]",evt=>{
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
        });
    }

    createElement() {
        super.createElement();
        this._itemsBox = this._handlers.content;
    }

    renderContext() {
        if (this.$required) {
            this.$metadata.validate.code = this.$validateCode;
        } else {
            this.$metadata.validate.code = null;
        }        
        super.renderContext();
        this._handlers.questionBody&&this._handlers.questionBody.html(this.$questionBody);
        if (this.root && this.root._isDesign && this.$metadata.dataSource) {
            if (this.$metadata.dataSource.type == 'vcode') {
                this.items = [];
            } else if (this.$metadata.dataSource.type == 'static') {
                this.items = this.$metadata.dataSource.code || [];
            }
        }
        if (this._itemsBox) {
            this.renderItems();
        }
    }

    renderReady() {
        let _this = this;
        super.renderReady();
        // dsf.UI.render("radio", true);
        layui.form.on('radio(' + this.id + ')', function(data) {
            $(data.elem).val(data.value);
            let isChange = data.value != _this.value;
            setValue.call(_this, data.value, true);
            if (isChange) {
                _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this });
            }
        });
    }

    renderItems() {
        if (this._itemsBox) {
            this._itemsBox.html("");
        }
        if (this.root._isDesign && this.items.length <= 0) {
            for (let i = 0; i < 2; i++) {
                let value = (i + 1);
                let name = this.name || this.id;
                let op = $("<input type='radio' " + (this.readOnly ? "disabled" : "") + " lay-filter='" + this.id + "' title='选项' name='" + (name) + "' value='" + value + "'/>");
                this._itemsBox.append(op);
            }
            if (this.isOther) {
                this._itemsBox.append("<input type='radio' " + (this.readOnly ? "disabled" : "") + " lay-filter='" + this.id + "' title='其他' />");
            }
        } else {
            //判断items中是否已经存在其他如果没有则追加一个
            if (this.isOther) {
                let otherItem = null;
                let index = _.findIndex(this.items, { "value": "else" });
                if (index >= 0) {
                    otherItem = this.items[index];
                    this.items.splice(index, 1);
                }
                if (!otherItem) {
                    otherItem = {
                        "text": "其他",
                        "value": "else",
                        "attach_text": ""
                    }
                }
                this.items.push(otherItem);
            }
            for (let i = 0; i < this.items.length; i++) {
                let item = this.items[i];
                if (item.attach_text == undefined) {
                    item.attach_text = ""
                }
                let name = this.name || this.id;
                let checked = false;
                if (this.value && (this.value.value == item.value)) {
                    checked = true;
                }
                let op = $("<input type='radio' " + (this.readOnly ? "disabled" : "") + " lay-filter='" + this.id + "' title='" + item.text + "' name='" + (name) + "' value='" + (item.value) + "' " + (checked ? "checked" : "") + "/>");
                this._itemsBox.append(op);
                if (item.value == "else") {
                    this._itemsBox.append('<div class="q_other"><input type="text"></div>');
                    if (this.value.value == "else") {
                        this._itemsBox.find(".q_other>input").val(this.value.attach_text || "")
                    }
                }
            }
        }
        renderRadio.call(this);

    }

    addItem(option, index, isRender) {
        if (index === undefined || index === null) {
            this.items.push(option);
        } else {
            this.items.splice(index, 0, option);
        }
        // this._itemDictionary[option.value] = option;
        if (isRender != false) {
            if (this._itemsBox) {
                this.renderItems();
            }
        }
    }

    getTextString() {
        if (this['$metadata']['defaultValue']) {
            return this.questionBody+this.$metadata.defaultValue.text;
        }
        return this.questionBody;
    }

    createMetaData(){
        let m = super.createMetaData();
        if (m.md.dataSource) {
            this.isOther? m.md.dataSource.attach = [{ "text": "其他", "value": "else"}]:m.md.dataSource.attach = [];
        }
        return m;
    }
}

//通过value字符串获取选项数据
function getItemByValueString(val) {
    let item = null;
    if (typeof(val) == "string") {
        item = _.find(this.items, { value: val });
    } else if (typeof(val) == "object") {
        item = _.find(this.items, { value: val.value });
    }
    return item;
}

//设置值
function setValue(val, flag) {
    let item = getItemByValueString.call(this, val);
    item ? this.$value = item : this.$value = { "text": "", "value": "", "attach_text": "" };
    if (val.attach_text != undefined) {
        this.$value.attach_text = val.attach_text;
    }
    if (this._itemsBox && this.$value.value) {
        //如果选择其他，则value中附加上用户输入的内容
        if (this.$value.value == "else") {
            //将附加文本的值赋给其他的文本框
            let attachInput = this._itemsBox.find("div.q_other>input")
            attachInput.val(this.$value['attach_text']);
        } else {
            let attachInput = this._itemsBox.find("div.q_other>input")
            attachInput.val("");
        }
        if (flag) {
            //使用click()默认用户点选，触发layui的radio选中时间
            this._itemsBox.find("input[value='" + this.$value.value + "']").prop("checked", true);
            checkedItem.call(this, item);
        }
        renderRadio.call(this);
    }
}

function checkedItem(item) {
    let elem = this._itemsBox.find("input[value='" + item.value + "']");
    if (elem.length > 0) {
        let data = {
            "elem": elem.get(0),
            "value": item.value
        }
        this.checkTrigHidden(data, this);
    }
}

function renderRadio() {
    if (isNaN(+this.colNum) || +this.colNum < 0 || +this.colNum > 10) {
        dsf.layer.message("请输入0~10之间的数字", false);
        dsf.UI.render("radio", true,null,'radio_' + this.id)
    } else {
        let _this = this;
        if(_this._isDesign){
            dsf.UI.render("radio", true, function() {
                var all = _this._itemsBox.find(".layui-form-radio");
                $(all).css("width", (100 / +_this.colNum).toFixed(2) + "%");
                if (_this.isOther) {
                    $(all).last().css("width", "auto");
                }
            }, 'radio_' + _this.id);
        }else{
            layui.form.render('radio','radio_' + _this.id);
            var all = _this._itemsBox.find(".layui-form-radio");
            $(all).css("width", (100 / +_this.colNum).toFixed(2) + "%");
            if (_this.isOther) {
                $(all).last().css("width", "auto");
            }
        }
    }
}
