import dom from '../templates/Fill.ejs';
import { QsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { controlBaseSetting } from '../../../decorator/controlBaseSetting';
import {map} from  '../../../decorator/controlmap';


const inputMinWidth = 60;   //对应html中也要修改
const inputMaxWidth = 300;  //对应html中也要修改


@map('填空题','dsf.qi.fill','Fill')
// const answerField = "answer";
@isSupportDataPost(true)
@controlBaseSetting("QAFillSetting2.html",'填空题',null,'480px')
export class Fill extends dsf.Controls.Question {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = QsMetaData.call(this);
        this.isNumber=0;
        //值
        this.$value = ""; //[];
    }
    initTemplate() {
        return dom(this);
    }
    render() {
        this.$metadata.validate.config.isNumber=this.isNumber;
        super.render();
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this.renderContext();
        }
    }

    set value(value) {
        this.$value = value;
        if (this._handlers.readOnlyLabel) {
            // loadData.call(this, value);
            // this._handlers.readOnlyLabel.text(this.getTextString(","));
        }
        loadData.call(this, value);
    }

    get value() {
        let _this = this;
        let inputs = this.element.find("input.filltext");
        let temp = [];
        inputs.each(function() {
            temp.push($(this).val());
        });
        if (temp.length <= 1) {
            this.$value = temp.join("");
        } else {
            this.$value = {};
            temp.forEach(function(o, i) {
                _this.$value["text_" + (i + 1)] = o;
            });
        }
        return this.$value;
    }

    renderContext() {
        let _this = this;
        super.renderContext();
        let content = this.getQuestionHtml();
        if (this._handlers.content) {
            this._handlers.content.html("")
            this._handlers.content.append(content);
        }

        loadData.call(this, this.$value);
    }

    getQuestionHtml() {
        let reg = /\(\)|（）/gi;
        let count = 1;
        let content = "";
        let _this = this;
        if (this.questionBody) {
            let str = this.questionBody.replace(reg, function(a, b, c) {
                let key = "text_" + (count);
                let html = "",type='text';
                _this.isNumber==1&&(type='number');
                if (!_this.readOnly) {
                    html = "<input type='"+type+"' placeholder='请输入' class='filltext' index='" + count + "' autocomplete='off' name='" + key + "'/>";
                } else {
                    html = "<input type='"+type+"' class='filltext' readonly='readonly' index='" + count + "' autocomplete='off' name='" + key + "'/>";
                }
                count++;
                return html;
            });
            content = str;
        } else {
            content = "请输入题干";
        }
        return content;
    }

    resize() {
        super.resize();
    }

    initEvent() {
        let _this = this;
        super.initEvent();
        let v = this.value;
        //输入文字时文本框自动延伸
        this.element.on("input", "input.filltext", function(evt) {
            let input = $(evt.target);
            inputReSize.call(_this, input);
            let content = input.val();
            if (typeof(this.value) == "string") {
                this.$value = content;
            } else {
                this.$value[input.attr("name")] = content;
            }
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this })
        })
    }

    createMetaData() {
        let m = super.createMetaData();
        if (m) {
            let meta = m.md;
            meta.valueAttributes = [];
            let inputs = this.element.find("input.filltext");
            inputs.each(function(i, el) {
                meta.valueAttributes.push({
                    "name": "文本" + (i + 1),
                    "code": "text_" + (i + 1),
                    "type": { text: "文本", value: "string" },
                    "length": "100",
                    "defaultValue": null,
                    "unit": null
                });
            })
            return m;
        }
        return null;
    }

}

function loadData(value) {
    if (this.element) {
        if (typeof(value) == "string") {
            let input = this.element.find("input[name='text_1']");
            input.val(value);
            inputReSize.call(this, input);
        } else if (typeof(value) == "object") {
            for (let k in value) {
                if (this.element) {
                    let input = this.element.find("input[name='" + k + "']");
                    input.val(value[k]);
                    inputReSize.call(this, input);
                }
            }
        }
    }

}

function inputReSize(input) {
    let content = input.val();
    this._handlers.fontsize.html(content);
    let width = this._handlers.fontsize.width();
    if (width < inputMinWidth) {
        width = inputMinWidth;
    } else if (width > inputMaxWidth) {
        width = inputMaxWidth;
    }
    input.css("width", width + "px");
}
