// import { widget } from '../../core/widget';
import { ControlEvent, PageEvent } from '../../core/ControlEvent';
import { map } from '../../decorator/controlmap';

@map('组件基类', 'dsf.control', 'Control')
// let control_type={};
export class Control {
  constructor(id, isPart) {
    if (!id) {
      id = dsf.uuid();
    }
    this.id = id;
    this.ctrl_type = this.getControlType();
    //是否被渲染
    this._isRender = false;
    this._viewRender = null;
    this.$useVdom = false;

    this.$background = {
      repeat: "",
      size: "",
      color: "",
      image: "",
      position: ""
    }

    //是否是独立控件
    this.isPart = isPart == true ? true : false;

    //当前组件元素
    this._element = null;
    //根组件对象
    this._root = null;
    //父组件对象
    this._parent = null;
    //可以操作元素句柄
    this._handlers = {};

    //设计器类
    this._desingerClass = null;
    //设计器对象
    this._desinger = null;

    //父控件元素
    this.parentElement = null;
    // this._placeholder = {
    //     start: document.createComment("ds:" + this.ctrl_type + ": start"),
    //     end: document.createComment("ds:" + this.ctrl_type + ": end")
    // }

    //设计模式下忽略拖拽时的感应
    this._dropIgnore = false;
    this._event = null;
    this.index = 0;
    //属性
    this.attrs = {};
    this.$classList = [];
    this.$styleList = {};
    this.$visible = true;
    this.$isFromMetaData = false;
    // this.$metadata = null;

    this.metadata_fullcode = "";
    this.webPath = dsf.config.webRoot;
    this.$hasDataScope = false;
    this.$dataBind = null;
    this.$tbNoPadding = false;
    this.$showPadding = true;
    this._validateError = null;
    this.$scopeLevel = 0;

    //是否是表单组件
    this._isFormControl = false;
    //是否是问卷类组件
    this._isQuestionControl = false;
    //是否是考试类组件
    this._isExamControl = false;
    //是否是容器类型组件
    this._isContainerControl = false;
    //是否是布局类型组件
    this._isLayoutControl = false;
    //是否是枚举类型组件
    this._isItemsControl = false;
    //是否是自定义html组件
    this._isCustomerControl = false;

    if (window.page) {
      this.root = window.page;
    }

  }
  get element() {
    return this._element;
  }
  set element(value) {
    this._element = value;
  }
  get parent() {
    return this._parent;
  }
  set parent(value) {
    this._parent = value;
  }

  get background() {
    return this.$background;
  }
  set background(v) {
    this.$background = v;
    if (this.element && !this.isDesign) {
      this.renderBackground()
    }
  }

  get root() {
    return this._root;
  }
  set root(val) {
    this._root = val;
  }
  get topControl() {
    let mctrl = this;
    let max = 20;
    let count = 0;
    while (mctrl.isPart && count < max) {
      if (mctrl == this.root) {
        return this.root;
      }
      mctrl = mctrl.parent;
      count++;
    }
    // console.log(count)
    return mctrl;
  }

  set caption(value) {
    this.$caption = value;
    if (this.element) {
      this.element.attr("caption", value);
    }
  }

  get caption() {
    return this.$caption;
  }

  get visible() {
    return this.$visible;
  }

  set tbNoPadding(value) {
    this.$tbNoPadding = value;
    value ? this.addClass("t_b_no_padding") : this.removeClass("t_b_no_padding")
  }
  get tbNoPadding() {
    return this.$tbNoPadding;
  }

  set showPadding(value) {
    this.$showPadding = value;
    value ? this.removeClass("no_padding") : this.addClass("no_padding");
  }
  get showPadding() {
    return this.$showPadding;
  }

  set visible(value) {
    this.$visible = value;
    if (!value) {
      this.addClass("ds_hide")
    } else {
      this.removeClass("ds_hide")
    }
  }
  set metadata(value) {
    this.$metadata = value;
  }

  get metadata() {
    return this.$metadata;
  }

  get isDesign() {
    return this.root._isDesign;
  }

  get event() {
    if (!this._event) {
      this._event = new ControlEvent(this);
    }
    return this._event;
  }

  set dataBind(value) {
    this.$dataBind = value;
    if (this.element) {
      this.element.attr("ds-data-bind", value);
    }
  }
  get dataBind() {
    return this.$dataBind;
  }

  init() {}

  initDesign() {}

  addClass(key) {
    if ($.isArray(key)) {
      for (let i = 0; i < key.length; i++) {
        this.addClass(key[i])
      }
    } else if (typeof(key) == "string") {
      if (this.$classList.indexOf(key) < 0) {
        this.$classList.push(key);
        if (this.element) {
          this.element.addClass(key);
        }
      }
    }
  }

  removeClass(key) {
    for (let i = this.$classList.length - 1; i >= 0; i--) {
      if (this.$classList[i] == key) {
        this.$classList.splice(i, 1);
      }
    }
    if (this.element) {
      this.element.removeClass(key);
    }
  }

  addStyle(key, value) {
    this.$styleList[key] = value;
    if (this.element) {
      this.element.css(key, value);
    }
  }
  removeStyle(key) {
    delete this.$styleList[key];
    if (this.element) {
      let css = this.element.get(0).style.cssText;
      let cssList = css.split(";");
      let temp = [];
      for (let i = 0; i < cssList.length; i++) {
        if (cssList[i]) {
          var s = cssList[i].split(":");
          if (s[0] != key) {
            temp.push(cssList[i]);
          }
        }
      }
      this.element.get(0).style.cssText = temp.join(";");
    }
  }
  addAttrs(key, value) {
    this.attrs[key] = value;
    if (this.element) {
      this.element.attr(key, value);
    }
  }
  removeAttrs(key) {
    delete this.attrs[key];
    if (this.element) {
      this.element.removeAttr(key);
    }
  }

  /**
   * 获取组件模板
   */
  initTemplate() {
    return "<div></div>";
  }

  /**
   * 创建组件元素方法
   */
  createElement() {
    if (!this.$useVdom) {
      if (!this._isRender) {
        this.init();
        let template = this.initTemplate();
        this.element = this.getTemplateElement(template);
        // this.event.trigger("createElement", { "ui": this });
        if (this.root && this.root._isDesign) {
          this.initDesign();
        }
      } else {
        let template = this.initTemplate();
        let newDom = this.getTemplateElement(template);
        let attributes = newDom.get(0).attributes;
        for (let i = 0; i < attributes.length; i++) {
          let attr = attributes[i];
          this.element.get(0).setAttribute(attr.nodeName, attr.nodeValue);
        }
        this.element.html(newDom.html());
        this._desinger = null;
      }
      this.createHandlers();
    } else {
      if (!this._isRender) {
        this.element = this.getTemplateElement("<div></div>");
      }
    }
  }

  initElement() {
    //计算所有样式
    let classStr = "ds_control ";
    this.$tbNoPadding ? this.addClass("t_b_no_padding") : this.removeClass("t_b_no_padding");
    classStr += this.$classList.join(" ");
    if (!this.isDesign) {
      if (this.metadata_fullcode) {
        this.$dataBind = this.metadata_fullcode;
      }
    }
    this.element.attr({
      "id": this.id,
      "ctrl_type": this.ctrl_type,
      "caption": this.caption
    });
    this.element.addClass(classStr);
    this.element.css(this.$styleList);
    this.element.attr(this.attrs);
    this.element.data("Object", this);
    if (!this.isDesign) {
      this.element.attr("ds-data-bind", this.dataBind);
    }
    if (this._dropIgnore && this.isDesign) {
      this.element.addClass("drop-ignore");
    }
  }

  getTemplateElement(template) {
    let html = $(template);
    let dom = null;
    if (html.length > 1) {
      for (let i = 0; i < html.length; i++) {
        if (html[i].nodeType == 1) {
          dom = html.eq(i);
          break;
        }
      }
    } else {
      dom = html;
    }
    return dom;
  }

  createHandlers() {
    let _handlers = this._handlers = {};

    function fn(element) {
      if (element.attributes["handler"]) {
        _handlers[element.attributes["handler"].nodeValue] = $(element);
      }
      for (let i = 0; i < element.childNodes.length; i++) {
        let node = element.childNodes[i];
        if (node.nodeType == 1) {
          fn(node)
        }
      }
    }
    fn(this.element.get(0));
  }

  //画背景
  renderBackground() {
    let background = this.getBackgroundStyle(this.$background);
    for (let k in this.$background) {
      this.element.css("background-" + k, "");
    }
    this.element.css(background);
  }

  getBackgroundStyle(background) {
    let css = {}
    if (background) {
      if (background.color) {
        css["background-color"] = background.color;
      }
      if (background.repeat) {
        css["background-repeat"] = background.repeat || 'no-repeat';
      }
      if (background.image) {
        css["background-image"] = "url('" + dsf.url.getAbsolutePath(background.image) + "')";
      }
      if (background.position) {
        css["background-position"] = background.position;
      }
      if (background.size) {
        css["background-size"] = background.size;
      }
    }
    return css;
  }

  /**
   * 更新组件内容方法
   */
  renderContext() {
    if (!this.isDesign) {
      this.renderBackground();
    }!this.visible ? this.addClass("ds_hide") : this.removeClass("ds_hide");
    if (this.showPadding) {
      this.removeClass("no_padding")
    } else {
      this.addClass("no_padding");
    }
  }

  /**
   * 创建子组件
   */
  renderChild() {

  }

  /**
   * dom创建或者更新完毕，可以对dom进行有效操作
   */
  renderReady() {
    //如果处于设计模式，则尝试读取设计器类
    if (this._root && this._root._isDesign) {
      if (!this._desinger && this._desingerClass) {
        this._desinger = new this._desingerClass(this);
        if (this._desinger.init) {
          this._desinger.init();
        }
      }
    } else {
      this.initEvent();
    }
  }

  /**
   * 组件元素渲染完成
   */
  renderComplete() {}


  // //渲染数据
  // renderData() {

  // }

  /**
   * 初始化事件
   */
  initEvent() {

  }

  /**
   * 重绘控件包含子控件
   */
  render(el) {
    this.createElement();
    if (!el) {
      let parentElement = Control.getParentDOMElementByExpress(this, this.parentElement);
      if (parentElement && parentElement.length > 0) {
        Control.renderToPos.call(this, parentElement);
      }
    } else {
      $(el).replaceWith(this.element);
    }
    if (this.$useVdom) {
      if (!this._viewRender) {
        this.createVdom();
      } else {
        this._viewRender.render();
      }
    }
    this.initElement();
    this.createHandlers();
    this.renderContext();
    this.element.data("Object", this);
    this.renderChild();
    this.renderReady();
    this.renderComplete();
    if (!this.root._isDesign) {
      this.root._childrenList[this.$caption] = this;
    }
    this._isRender = true;
    if (this.isDesign) {
      this.renderData && this.renderData();
    } else {
      if (!this.root._ready && this.renderData) {
        this.root.event.on(PageEvent.READY, args => {
          this.renderData();
        });
      } else {
        this.renderData && this.renderData();
      }
    }
  }


  remove() {
    let parent = this.parent;
    if (parent && parent.removeChild) {
      parent.removeChild(this);
    }
    delete this.root._childrenList[this.caption];
    this.root.event.trigger(PageEvent.REMOVECONTROL, {
      ui: this
    });
  }

  /**
   * 刷新设计器
   */
  renderDesginer() {
    if (this._root._isDesign) {
      if (this._desinger && this._desinger.renderDesginer) {
        this._desinger.renderDesginer();
      }
    }
  }

  /**
   * 获取当前控件名称
   */
  getControlType() {
    // Reflect.construct(this.constructor)
    if (this.constructor.name) {
      return this.constructor.name;
    } else {
      var s = this.constructor.toString();
      if (s.indexOf('function') == -1) {
        return null;
      } else {
        s = s.replace('function', '');
        var idx = s.indexOf('(');
        s = s.substring(0, idx);
        s = $.trim(s)
      }
      return s;
    }
  }

  getTextString(split) {
    return "";
  }
  getValueString(split) {
    return "";
  }

  /** 
   * 重置尺寸
   */
  resize() {}

  //创建元数据
  createMetaData() {

  }

  emitDataChange(target, currentTarget, data) {}

  getControlJson() {
    let layout = JSON.stringify(this, function(key, val) {
      // console.log(key)
      // console.log(key)
      if (key.indexOf("_") != 0) {
        return val;
      }

      return undefined;
    });
    return layout;
  }

  getControlById(id) {
    let ctrl = $("#" + id).data("Object");
    return ctrl;
  }



  findControls(select) {
    let el = this.element.find(select);
    let ctrls = [];
    for (let i = 0; i < el.length; i++) {
      let e = el.eq(i);
      let ctrl = e.data("Object");
      ctrls.push(ctrl);
    }
    return ctrls
  }

  validateError(value, errorMsg) {

  }

  //描述组件的验证信息
  validateInfo() {
    return {
      tipsElement: "", //".layui-form-select input.layui-input"
    }
  }

  showTips(message, selector, pos, time) {
    let _this = this;
    if (this.element) {
      let posMap = {
        "left": 4,
        "top": 1,
        "bottom": 3,
        "right": 2
      }
      if (!this.element.data("isShow")) {
        let el = this.element;
        if (selector) {
          if (typeof(selector) == "string") {
            el = this.element.find(selector);
            console.log(el);
          }
          //说明是个jquery对象
          else if (selector.jquery) {
            el = selector;
          } else {
            el = $(selector);
          }
        }
        let index = layui.layer.tips(message, el.get(0), {
          tips: posMap[pos],
          time: time == undefined ? 2000 : time,
          tipsMore: true,
          end: function() {
            _this.element.data("tipsIndex", null);
            _this.element.data("isShow", false)
          }
        });
        this.element.data("isShow", true)
        this.element.data("tipsIndex", index)
      }
    }
  }
  hideTips() {
    let index = this.element.data("tipsIndex");
    if (index) {
      layui.layer.close(index);
    }
    this.element.data("tipsIndex", null);
    this.element.data("isShow", false)
  }


  //新增的vdom函数
  createVdom() {
    let _this = this;
    if (!this._viewRender) {
      this._viewRender = dsf.vdom({
        el: this.element.get(0),
        template: this.initTemplate(),
        data: this,
        inserted: function(vnode, vm) {
          _this.element = $(vnode.elm);
          _this._isRender = true;
          _this.element.data("Object", _this);
          _this._viewRender = this;
          _this.inserted && _this.inserted(vnode.elm);
        },
        updated: function(oldVnode, vnode) {
          _this.element = $(vnode.elm);
          _this.element.data("Object", _this)
          _this.updated && _this.updated(vnode.elm);
        }
      })
    }
  }
  inserted() {}
  updated() {}
  domUpdate() {
    this._viewRender && this._viewRender.render();
  }

  //新增的vdom函数


  static getParentDOMElementByExpress(control, express) {
    if (express) {
      if (!control.parent) {
        return $(express);
      } else {
        // console.time("测试"+control.id)
        let box = null;
        if (control.parent && control.parent._handlers[express]) {
          box = control.parent._handlers[express]
        }
        if (box && box.length > 0) {
          return box;
        }
        // console.timeEnd("测试"+control.id)
        return control.parent.element;
      }
    }
    return null;
  }

  static renderToPos(parentElement) {
    // console.time(this.id+"_"+this.ctrl_type+"_"+this.html)
    //根节点
    if (this == this.root) {
      parentElement.append(this.element);

    } else {
      if (parentElement && parentElement.length > 0) {
        if (this.parent && this.parent.children) {
          let index = this.index;
          let nextCtrl = this.parent.children[index + 1];
          if (nextCtrl && nextCtrl.element && dsf.Dom.isDOMInner(document, nextCtrl.element.get(0))) {
            $(nextCtrl.element).before(this.element)

          } else {

            parentElement.append(this.element);
          }
        } else {

          parentElement.append(this.element);
        }
      } else {
        this.parent.element.before(this.element);

      }
    }
    // console.timeEnd(this.id+"_"+this.ctrl_type+"_"+this.html)
  }
}

function getTemplateElement(template) {
  let html = $(template);
  let dom = null;
  if (html.length > 1) {
    for (let i = 0; i < html.length; i++) {
      if (html[i].nodeType == 1) {
        dom = html.eq(i);
        break;
      }
    }
  } else {
    dom = html;
  }
  return dom;
}

function checkedTag(node, parent, currCtrl, parentElement) {
  if (node) {
    if (node.nodeName) {
      let type = node.nodeName.toLowerCase()
      if (type.indexOf("dsf-") == 0) {
        let tag = type.replace(/\-/g, '.');
        if (window._controlMap.code[tag]) {
          let ctor = window._controlMap.code[tag].handler;
          let id = node.getAttribute("id")
          let ctrl = new ctor(id, true);
          if (parent.nodeName && parent.nodeType) {
            ctrl.parentElement = parent.getAttribute("handler");
          } else {
            parent._addChild(ctrl);
          }
          if (node.childNodes && node.childNodes.length > 0) {
            checkedTag(node.childNodes[i], ctrl, currCtrl);
          }
          // if (parent == currCtrl) {
          //     debugger;
          //     // ctrl.render($(node));
          // }
        }
      } else {
        if (node.childNodes && node.childNodes.length > 0) {
          for (var i = 0; i < node.childNodes.length; i++) {
            checkedTag(node.childNodes[i], node, currCtrl);
          }
        }
      }
    }
  }
}