import dom from '../templates/QsHelloMsg.ejs';
import {Control} from "../../../baseControls";
import { ControlEditor } from '../../../editor/ControlEditor';
import { controlBaseSetting } from '../../../decorator/controlBaseSetting';
import {map} from  '../../../decorator/controlmap';

@map('欢迎语','dsf.qi.hello','QsHelloMsg')
@controlBaseSetting("QSDialogHello.html","欢迎语设置",null,null)
export class QsHelloMsg extends Control{
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    //值
    this.$questionBody="";
    this._noBorder = false;
  }

  initTemplate() {
    return dom(this);
  }

  render() {
    super.render();
  }

  get questionBody() {
    return this.$questionBody
  }

  set questionBody(value) {
    this.$questionBody = value;
    if (this.element) {
      this.renderContext();
    }
  }

  renderContext() {
    super.renderContext();
    this._handlers.content.html("");
    this._handlers.content.append(this.$questionBody);
  }

  resize() {
    super.resize();
  }

}
