import { FormControl } from './FormControl';
import { ItemMetaData, vattType } from '../../core/metadata';
import { FormControlEvent } from '../../core/ControlEvent';

import { map } from '../../decorator/controlmap';

@map('枚举基类', 'dsf.itemscontrol', 'ItemsControl')

export class ItemsControl extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    this._items = [];
    this._itemsBox = null;
    this.$metadata = ItemMetaData.call(this);
    this.$value = { "text": "", "value": "" };
    this.$allowMulti = true;
    // this.$metadata.valueAttributes.push(metaDataHelper.createMetaValueAttributes("值", "value", "string", "50", null, null));
    // 是否有“其他”选项
    this.$isOther = false;
    this._isItemsControl = true;
  }

  get items() {
    return this._items;
  }
  set items(value) {
    this._items = [];
    for (let i = 0; i < value.length; i++) {
      let isRender = i == value.length - 1 ? true : false;
      this.addItem(value[i], i, isRender);
    }
    if (this._items.length <= 0) {
      this.renderItems();
    }
  }

  get itemsBox() {
    return this._itemsBox;
  }

  set value(value) {
    let o_value = this.$value;
    this.$value = value;
    if (typeof(value) == "string" || typeof(value) == "number") {
      for (let i = 0; i < this._items.length; i++) {
        if (this._items[i].value == value) {
          this.$value = this._items[i];
          break;
        }
      }
    } else if (typeof(value) == "object") {
      let val = (value && value.value != undefined) ? value.value : ""; // this.value ? this.value.value : null;
      for (let i = 0; i < this._items.length; i++) {
        if (this._items[i].value == val) {
          this.$value = this._items[i];
          if (val == 'else' && value.attach_text) {
            this.$value.attach_text = value.attach_text;
          }
          break;
        }
      }
      if (dsf.isEmpty(val)) {
        this.$value = o_value;
      }
    }
  }

  get value() {
    return this.$value;
  }

  set isOther(value) {
    this.$isOther = value;
    if (this.element) {
      this.renderContext();
    }
  }
  get isOther() {
    return this.$isOther;
  }

  initTemplate() {
    return dom(this);
  }

  renderContext() {
    super.renderContext();
    //兼容已经配置好的页面,没其他什么卵用
    if (!this.$metadata.dataSource) {
      if (this.$metadata.datasource) {
        this.$metadata.dataSource = this.$metadata.datasource;
      } else {
        this.$metadata.dataSource = {
          "code": [],
          "type": "static"
        }
      }
      if (this.$items && this.$items.length > 0) {
        this.$metadata.dataSource.code = this.$items;
      }
    }
    if (this.root && this.root._isDesign) {
      if (this.$metadata.dataSource.type == 'vcode') {
        this.items = [];
      } else if (this.$metadata.dataSource.type == 'static') {
        this.items = this.$metadata.dataSource.code || [];
      }
    }
    if (this._itemsBox) {
      this.renderItems();
    }
  }
  renderReady() {
    super.renderReady();
  }

  addItem(option, index, isRender) {
    if (index === undefined || index === null) {
      this.items.push(option);
    } else {
      this.items.splice(index, 0, option);
    }
    // this._itemDictionary[option.value] = option;
    if (isRender != false) {
      if (this._itemsBox) {
        this.renderItems();
      }
    }
  }

  renderItems() {
    if (!this.readOnly) {
      if (this._itemsBox) {
        this._itemsBox.html("");
      }
    }
  }


  getTextString(split) {
    if (this.value) {
      return this.value.text;
    }
  }
  getValueString(split) {
    if (this.value) {
      return this.value.value;
    }
  }

  createMetaData() {
    let m = super.createMetaData();
    if (m.md.dataSource) {
      if (this.isOther) {
        m.md.dataSource.attach = [{ "text": "其他", "value": "else" }];
        if (m.md.valueAttributes.length < 3) {
          m.md.valueAttributes.push({
            "name": "附加文本",
            "code": "attach_text",
            "type": $.extend({}, vattType["string"]),
            "length": "200",
            "defaultValue": null,
            "unit": null
          })
        }
      } else {
        m.md.dataSource.attach = [];
        if (m.md.valueAttributes.length == 3) {
          m.md.valueAttributes.length = 2
        }
      }
    }
    return m;
  }
}