import dom from '../templates/QsSlider.ejs';
import { QsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import {controlBaseSetting} from "../../../decorator/controlBaseSetting";
import {map} from  '../../../decorator/controlmap';

@map('滑块题','dsf.qi.slider','QsSlider')
@controlBaseSetting("QSSlider.html","滑块题",null,"530px")
@isSupportDataPost(true)
export class QsSlider extends dsf.Controls.Question {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$max = 100;
        this.$min = 0;
        this.$step = 1;
        this.$value = 0;
        this.$maxText = "";
        this.$minText = "";

        this.$metadata = QsMetaData.call(this);
        //题干
        this.$questionBody = "";

        this._ins1 = null;
    }
    initTemplate() {
        return dom(this);
    }
    render() {
        super.render();
    }

    get step(){
        return this.$step;
    }

    set step(value){
        this.$step = value;
    }
    get maxText() {
        return this.$maxText;
    }

    set maxText(value){
        this.$maxText = value;
    }

    get minText() {
        return this.$minText;
    }

    set minText(value){
        this.$minText = value;
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this._handlers.questionBody.html(this.$questionBody);
        }
    }

    set value(value) {
        this.updateShowValue(value);
        if (this.element) {
            this._ins1.setValue(parseFloat(value));
        }
    }

    get value() {
        return this.$value;
    }

    set max(value) {
        if(value<=this.$min){
            layer.msg("不能小于最小值", { icon: 5 });
            return
        }
        if (isNaN(+value)) {
            layer.msg("请输入数字", { icon: 5 });
            return
        }
        this.$max = +value;
    }

    get max() {
        return this.$max;
    }

    set min(value) {
        if(value>=this.$max){
            layer.msg("不能大于最大值", { icon: 5 });
            return
        }
        if (isNaN(+value)) {
            layer.msg("请输入数字", { icon: 5 });
            return
        }
        this.$min = +value;
        this.value=this.$min;
    }

    get min() {
        return this.$min;
    }

    set step(value) {
        if (isNaN(+value)) {
            layer.msg("请输入数字", { icon: 5 });
            return
        }
        this.$step = +value;
    }

    get step() {
        return this.$step;
    }

    renderContext() {
        super.renderContext();
        let content = "<div id='" + this.$questionIndex + "'></div>";
        if(this._handlers.content){
            this._handlers.content.html("");
            this._handlers.content.append(content);
        }
        this.renderSlider();
    }

    resize() {
        super.resize();
    }

    renderSlider() {
        let _this = this;
        var slider = layui.slider;
        this._ins1 = slider.render({
            elem: '#' + this.$questionIndex,
            value: parseFloat(this.$value || 0),
            max: this.$max,
            min: this.$min,
            step: this.$step,
            disabled:this.readOnly,
            setTips: function(value){ //自定义提示文本
                _this.updateShowValue(value);
                if( _this.$maxText && value == _this.$max*1){
                    value = _this.$maxText;
                }else if(_this.$minText && value == _this.$min*1){
                    value = _this.$minText;
                }
                return value;
            }
        })
    }

    updateShowValue(value) {
        this.$value = value;
        this._handlers.number.html(value);
    }
}
