const dom = require("../templates/Tab.ejs");

import {
	LayoutControl
} from "./LayoutControl";
import {
	Container
} from "./Container";
import {
	TabEvent
} from '../../core/ControlEvent';
import {
	map
} from '../../decorator/controlmap';

@map('tab基类', 'dsf.tabcontrol', 'TabControl')
export class TabControl extends LayoutControl {
	constructor(id, isPart) {
		super(id, isPart);
		// 页签数据
		this.tabTitles = [];
		// 组件高度
		this.tabHeight = '100%';
		// 组件风格
		this.tabStyle = 'layui-tab-brief';
		// 徽章样式
		this.badgeStyle = '';
		// 被点击的最后一个有效的lay-id
		this._layId = null;
		this._actI = 0;
	}
	// set tabHeight(val){
	//     this.$tabHeight=val;
	//     this.render()
	// }
	// get tabHeight(){
	//     return this.$tabHeight;
	// }
	init() {
		if (this.tabTitles.length == 0) {
			this.tabTitles = [{
					title: "Tab1",
					id: dsf.uuid(),
					disable: "0"
				},
				{
					title: "Tab2",
					id: dsf.uuid(),
					disable: "0"
				},
				{
					title: "Tab3",
					id: dsf.uuid(),
					disable: "0"
				}
			]
		}
	}
	initTemplate() {
		return dom(this);
	}
	createElement() {
		var el = super.createElement();
		this._tabTitleBox = this._handlers["layui-tab-title"];
		this._tabContentBox = this._handlers["layui-tab-content"];
		return el;
	}
	renderDom() {
		this.renderContext(true);
	}
	renderReady() {
		super.renderReady()
		if (this.root && this._root._isDesign) {
			$('.ds_tab .layui-tab-content .layui-tab-item').removeClass("no_padding")
		}
		let _this = this;
		layui.element.on('tab(' + this.id + ')', function(data) {
			if (!_this._root._isDesign) {
				if (_this.tabTitles[$(this).index()].disable == "1") {
					layui.element.tabChange(_this.id, _this._layId);
				} else {
					_this._layId = $(this).attr("lay-id");
					_this.event.trigger(TabEvent.SELECT, {
						ui: _this,
						args: {
							data: data
						}
					});
				}
			}
			// let content = $(data.elem).find(".layui-tab-item").eq(data.index);
			let content = $(data.elem).find(".ds_container.layui-show");
			let iframes = content.find(".ds_iframe");
			let contentCtrl = content.data("Object");

			contentCtrl.resize();

			function triggerReady(page) {
				if (page) {
					page.event.trigger(PageEvent.READY);
				}
			}
			iframes.each(function(i, el) {
				let iframeCtrl = $(this).data("Object");
				let iframeEl = $(this).find("iframe").get(0);
				if (iframeCtrl) {
					if (!iframeCtrl._isLoaded && iframeCtrl.$lazyLoad) {
						iframeCtrl.loadView();
					} else {
						triggerReady(iframeEl.contentWindow.page);
					}
				} else {
					triggerReady(iframeEl.contentWindow.page);
				}

			})
		});
	}
	renderContext(isUpdate) {
		this._actI = 0;
		// 更新Tab标题
		this.renderTabTitles();
		// 更新Tab内容
		if (!(!isUpdate && this.children.length > 0)) {
			this.renderTabContent(isUpdate);
		}
		this.resizeHeight()
	}
	renderTabTitles(activeIndex) {
		if(this.root._isRender){
			this._renderTabTitles(activeIndex);
		}else{
			this.root.event.on(PageEvent.READY, evt => {
				this._renderTabTitles(activeIndex);
			});
		}
	}
	_renderTabTitles(activeIndex){
		this._tabTitleBox.html("");
		let l = this.tabTitles.length;
		for (let i = l - 1; i >= 0; i--) {
			if (this.tabTitles[i].hide) {
				this.tabTitles.splice(i, 1);
			} else {
				let badge = "";
				if (!this._root._isDesign && this.tabTitles[i].badge) {
					badge = "<span class='layui-badge' id='" + this.tabTitles[i].id + "_badge'>0</span>";
				}
				let _disable = "";
				let isdis = (this.tabTitles[i].disable == "1");
				if (!this._root._isDesign) {
					_disable = " disable='" + isdis + "'";
				}
		
				let li = $("<li lay-id='" + i + "'" + _disable + " >" + this.tabTitles[i].title + badge + "</li>");
		
				//2019-3-28 翁伟勇 增加页签是否隐藏功能
				if (dsf.Express.eval(this.tabTitles[i].isHide || 0)) {
					li.addClass("ds_hide");
				} else {
					li.removeClass("ds_hide");
					if (!isdis) {
						this._actI = i;
					}
				}
				this._tabTitleBox.prepend(li);
			}
		}
		if (this._actI > 0) {
			let _this = this;
			this._root.event.on(PageEvent.INITED, () => {
				this.tabChange(_this._actI);
			})
		}
		
		if (this._tabTitleBox.find('li')[activeIndex || this._actI]) {
			$(this._tabTitleBox.find('li')[activeIndex || this._actI]).addClass('layui-this');
			this._layId = activeIndex || this._actI;
		}
		layui.element.render(this.id);
	}
	cancelDisable() {
		for (let i in this.tabTitles) {
			this.tabTitles[i].disable = "0";
		}
		this.renderTabTitles();
	}

	showTabItem(index) {
		this.tabTitles[index].isHide = 0;
		// let id = this.tabTitles[index].id;
		if (this.element) {
			let li = this.element.find("[lay-id=" + index + "]");
			li.removeClass("ds_hide");
		}
	}
	hideTabItem(index) {
		this.tabTitles[index].isHide = 1;
		// let id = this.tabTitles[index].id;
		if (this.element) {
			let li = this.element.find("[lay-id=" + index + "]");
			li.addClass("ds_hide");
		}
	}

	renderTabContent(isUpdate, renderContentIndex) {
		this._tabContentBox.html("");
		let newChidren = [];
		let hasChildrenL = this.children.length;

		for (let i = this.tabTitles.length - 1; i >= 0; i--) {
			let key = this.tabTitles[i].contentKey = this.tabTitles[i].id + "_content";

			// 在children里面寻找对应容器，没找着就新创建容器
			let container = null;
			if (hasChildrenL > 0) {
				for (let j = 0; j < this.children.length; j++) {
					if (this.children[j].id == key) {
						container = this.children[j];
						break;
					}
				}
			}
			if (!container) {
				container = new Container(key, true);
				this._addChild(container, null, "layui-tab-content");
			}

			// 根据需求修改容器Class
			container.addClass(["layui-tab-item", "no_padding"]);
			if (renderContentIndex && i == renderContentIndex) {
				container.addClass("layui-show");
			} else if (!renderContentIndex && i == this._actI) {
				container.addClass("layui-show");
			} else {
				container.removeClass("layui-show");
			}
			newChidren.unshift(container);
		}
		this.children = newChidren;
		if (isUpdate) this.renderChild();
	}
	changeStyle() {
		this.removeClass('layui-tab-brief');
		this.removeClass('layui-tab-card');
		if (this.tabStyle) this._handlers["ds_tab"].removeClass().addClass("ds_tab layui-tab " + this.tabStyle);
	}
	resizeHeight() {
		this.addStyle('height', this.tabHeight);
	}
	renderComplete() {
		let _this = this;
		super.renderComplete();
		_this.root.event.on(PageEvent.READY, evt => {
			_.forEach(this.tabTitles, function(val, key) {
				if (val.badge) {
					_this.event.trigger(TabEvent.BADGE, {
						"ui": _this,
						"args": {
							"actionName": val.badge,
							"ui": $('#' + val.id + '_badge')
						}
					});
				}
			})
		});

	}
	tabChange(index) {
		// 切换tab
		layui.element.tabChange(this.id, index);
	}
}
