function destroyToolTips() {
  $(this).off('mouseenter.tooltips')
  $(this).off('mouseleave.tooltips')
  $(this).removeClass('ds_error')
}

function changeSelectValue(data, chooseType, isInput, noTrigger, type) {
  if (data) {
    let index = chooseType
      ? data.attr('index')
      : data.elem.getAttribute('index')
    let value = chooseType
      ? isInput
        ? data.val()
        : data.attr('value')
      : data.value
    value = (value * 1).toFixed('2')
    index = index.split('_')
    if (index.length == 1) {
      this.rowSet.rows[index[0]].score = value
    } else {
      this.rowSet.rows[index[0]].children[index[1]].score = value
    }
  }
  let total = 0
  let length = 0

  for (let i in this.rowSet.rows) {
    let obj = this.rowSet.rows[i]
    if (obj.weight) {
      total += ((obj.score || 0) * obj.weight) / 100
    } else {
      total += (obj.score || 0) * 1
    }
    if (!obj.children) {
      length++
    }
    _.forEach(obj.children, function(_val, _key) {
      length++
      if (_val.weight) {
        total += ((_val.score || 0) * _val.weight) / 100
      } else {
        total += (_val.score || 0) * 1
      }
    })
  }
  if (!noTrigger) {
    this.changeTotal(total)
  }
  this.total = total
  if (this.rowSet.weight == '0') {
    total = total / length
  }
  this.rowSet.total = total.toFixed(2)
  if (!chooseType) {
    this.render()
  }
}
