import dom from '../templates/QA.ejs';
import { QsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { controlBaseSetting } from '../../../decorator/controlBaseSetting';
import {map} from  '../../../decorator/controlmap';

@map('问答题','dsf.qi.qa','QA')
@controlBaseSetting("QA2.html", '问答题', null, '480px')
@isSupportDataPost(true)
export class QA extends dsf.Controls.Question {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$metadata = QsMetaData.call(this);
        this.$validateCode = this.$metadata.validate.code;
        //值
        this.$value = "";
        this.$placeholder = "请输入";
        this.$isTextArea = false;
        this.$maxLength = 0;
    }
    initTemplate() {
        return dom(this);
    }
    render() {
        super.render();
    }
    get maxLength() {
        return this.$maxLength;
    }

    set maxLength(value) {
        this.$maxLength = value;
        this.setAstrictMsg();
    }

    get placeholder() {
        return this.$placeholder;
    }
    set placeholder(value) {
        this.$placeholder = value;
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this.renderContext();
        }
    }

    set isTextArea(value) {
        this.$isTextArea = value;
    }
    get isTextArea() {
        return this.$isTextArea;
    }

    set value(value) {
        this.$value = value;
        if (this.element) {
            this.element.find(".filltext").val(value);
        }
        if (this._handlers.readOnlyLabel) {
            this._handlers.readOnlyLabel.text(this.getTextString(","));
        }
    }

    get value() {
        return this.$value
    }

    renderContext() {        
        if (this.$required) {
            this.$metadata.validate.code = this.$validateCode;
        } else {
            this.$metadata.validate.code = null;
        }        
        super.renderContext();
        this.setAstrictMsg(true);
    }

    initEvent() {
        let _this = this;
        super.initEvent();
        let v = this.value;
        //输入文字时文本框自动延伸
        this.element.on("input", ".filltext", function (evt) {
            let input = $(evt.target);
            _this.$value = input.val();
            _this.event.trigger(FormControlEvent.VALUECHANGE, { ui: _this })
            _this.setAstrictMsg();
        })
    }

    createMetaData() {
        let m = super.createMetaData();
        if (m) {
            let meta = m.md;
            meta.valueAttributes[0].length = 500;
            return m;
        }
        return null;
    }

    setAstrictMsg(isInit) {
        let $dom = this._handlers['astrict-msg'];
        if ($dom) {
            let msg = null,
                max_l = this.$maxLength ? this.$maxLength : 200,
                val_l = this.$value.length,
                gap = max_l-val_l;

            $dom.removeClass('error');

            if (isInit && !this.$value) {
                msg = "字数统计"
            } else if (gap < 0) {
                $dom.addClass('error');
                msg = '字数超出最大限制，服务器可能拒绝保存！'
            } else {
                msg = '已输入' + val_l + '字符, 您还可以输入' + gap + '字符。'
            }
            $dom.html(msg);
        }
    }

}
