import dom from '../templates/QsRate.ejs';
import { QsMetaData } from '../../../core/metadata';
import { isSupportDataPost } from '../../../core/postDecorator';
import { FormControlEvent } from '../../../core/ControlEvent';
import { controlBaseSetting } from '../../../decorator/controlBaseSetting';
import {map} from  '../../../decorator/controlmap';

@map('评分题','dsf.qi.rate','QsRate')
@controlBaseSetting("QSRate2.html","评分题",null,'510px')
@isSupportDataPost(true)
export class QsRate extends dsf.Controls.Question {
    constructor(id, isPart) {
        super(id, isPart);
        this.$label = "";
        this.$StarLength = 5;
        this.$showText = false;
        this.$value = 0;

        this.$metadata = QsMetaData.call(this);
        this.$validateCode = this.$metadata.validate.code;
        //题干
        this.$questionBody = "";
    }
    initTemplate() {
        return dom(this);
    }
    render() {
        let _this = this;
        super.render();
    }

    get questionBody() {
        return this.$questionBody
    }

    set questionBody(value) {
        this.$questionBody = value;
        if (this.element) {
            this._handlers.questionBody.html(this.$questionBody);
        }
    }

    set showText(value) {
        this.$showText = value;
        if (this.element) {
            this.renderContext();
        }
    }

    get showText() {
        return this.$showText;
    }

    set StarLength(value) {
        this.$StarLength = value;
        if (this.element) {
            this.renderContext();
        }
    }

    get StarLength() {
        return this.$StarLength;
    }

    set value(value) {
        super.value = value;
        if(this.element){
            this.renderRate();
        }
    }

    get value() {
        return this.$value;
    }

    renderContext() {
        if (this.$required) {
            this.$metadata.validate.code = this.$validateCode;
        } else {
            this.$metadata.validate.code = null;
        }
        super.renderContext();
        let content = "<div id='" + this.$questionIndex + "'></div>";
        if(this._handlers.content){
            this._handlers.content.html("");
            this._handlers.content.append(content);
        }
        this.renderRate();
    }

    resize() {
        super.resize();
    }

    renderRate(){
        let _this=this;
        var rate = layui.rate;
        rate.render({
            elem: '#' + this.$questionIndex,
            value: parseFloat(this.$value),  //初始值
            readonly:this.readOnly,
            text: this.$showText,
            length: this.$StarLength,
            half: true, //开启半星
            choose: function(value) {
                _this.value = value;
            }
        })
    }


}
