import { isSupportDataPost } from '../../core/postDecorator';
import { oneToMany } from "../../decorator/oneToMany";
import { LayoutControl } from './LayoutControl';
import { map } from '../../decorator/controlmap';

@map('子表基类', 'dsf.childrenlist', 'ChildrenList')
@isSupportDataPost(true)
@oneToMany
export class ChildrenList extends LayoutControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$readOnly = false;
    this.$columns = [];
    this.$showLabel = false;
    this.$label = "子表标题";
    this.value = [];
    this.$scopeLevel = 1;
    this._deleteData = {};
    this.$autoOrderByIndex = true;
  }

  // setValue(index, code, value) {
  //     let fullCode = this.metadata_fullcode + "." + code;
  //     let d = this.data;
  //     d[index][fullCode] = value;
  //     if (this.element) {
  //         let ctrlEl = this.element.find("[ds-data-bind='" + fullCode + "']");
  //         let ctrl = ctrlEl.data("Object");
  //         if (ctrl) {
  //             ctrl.value = value;
  //             d[fullCode] = ctrl.value;
  //         }
  //     }
  // }


  //劫持表单组件的VALUE属性
  defineControlSetValue(ctrl) {
    let _this = this;
    if (ctrl._isFormControl) {
      let v = null;
      let formControl = ctrl;
      do {
        v = Object.getOwnPropertyDescriptor(formControl, "value");
        if (!v) {
          formControl = Object.getPrototypeOf(formControl);
        }
      } while (!v && formControl)

      if (v) {
        let setter = v.set || null;
        let getter = v.get || null;
        let val = v.value;
        Object.defineProperty(ctrl, "value", {
          enumerable: false,
          configurable: false,
          get: function() {
            if (getter) {
              return getter.call(ctrl);
            } else {
              return val;
            }
          },
          set: function(v) {
            if (setter) {
              setter.call(ctrl, v);
            } else {
              val = v
            }
            let arr = ctrl.caption.split("_");
            let rowindex = arr[1];
            if (_this.value[rowindex]) {
              _this.value[rowindex][ctrl.metadata_fullcode] = ctrl.value;
            }
          }
        });
      }
    }
  }
}