import { FormControlEvent } from '../../core/ControlEvent';
import { FormControl } from './FormControl';
import { map } from '../../decorator/controlmap';

@map('问卷基类', 'dsf.question', 'Question')

export class Question extends FormControl {
  constructor(id, isPart) {
    super(id, isPart);
    this.$value = null;
    this.$label = "";
    this.$readOnly = false;
    this.$required = true;
    this.$questionIndex = "";
    this.$questionBody = "";
    // 当前题目设置的跳过哪个题目
    this.$logic = "";
    // 当前题目被关联的题目
    this.$logicRela = [];
    this._logicMark = {};
    this._isQuestionControl = true;
    // 归类,用于统计
    this.group = "";
  }

  set label(value) {
    this.$label = value;
  }

  get label() {
    return this.$label;
  }

  set value(value) {
    this.$value = value;
  }

  get value() {
    return this.$value;
  }

  get questionIndex() {
    return this.$questionIndex;
  }

  set questionIndex(value) {
    this.$questionIndex = value;
    if (this.element) {
      this._handlers.index.html(this.$questionIndex + ":")
    }
    // 判断是否存在隐藏题目在此之前
    if (this.$logic) {
      let _this = this;
      for (let i = 0; i < this.$logic.length; i++) {
        let item = this.$logic[i];
        let curr = item['Q'].toString().replace('Q', ''),
          own = _this.$questionIndex.toString().replace('Q', '');
        if (curr * 1 <= own * 1) {
          this.$logic.splice(i, 1);
          i--;
        }
      }
    }
  }

  get questionBody() {
    return this.$questionBody;
  }

  set questionBody(value) {
    this.$questionBody = value;

  }

  get logicRela() {
    return this.$logicRela;
  }

  set logicRela(v) {
    this.$logicRela = v;
  }

  get logic_rela() {
    return this.$logic_rela;
  }

  set logic_rela(v) {
    let _this = this;
    this.$logic_rela = v;
    if (this._root.isDesign) {
      if (v.trig && v.trig.length > 0) {
        // 选了有值后才有效
        this.visible = false;

      } else {
        this.visible = true;
      }
    } else if (v.trig) {
      _.forEach(v.trig, (val, key) => {
        _this.addLogicMark("rela_" + _this.$questionIndex, val);
      })
    }
  }

  initEvent() {}

  createElement() {
    super.createElement();
    this.element.addClass("ds_question");
    this.element.attr('data-qid', this.$questionIndex);
  }

  set readOnly(value) {
    this.$readOnly = value;
    if (this._isRender) {
      this.render();
    }

  }

  get readOnly() {
    return this.$readOnly;
  }

  set metadata(value) {
    super.metadata = value;
  }

  get metadata() {
    return super.metadata;
  }

  getTextString() {
    return this.questionBody + (this['$metadata']['defaultValue'] || '');
  }

  getValueString(split) {
    return this.value;
  }

  set logic(value) {
    this.$logic = value;
  }

  get logic() {
    return this.$logic;
  }

  get logicMark() {
    return this._logicMark;
  }

  createMetaData() {
    if (this.metadata) {
      if(!!this.group){
        if(this.metadata.md){
          this.metadata.md['group'] = this.group;
        }else{
          this.metadata['group'] = this.group;
        }
      }
      
      if (!this.$isFromMetaData) {
        let key = this.root.scope;
        let controlCode = this.$caption;
        let ns = key;
        key += "." + controlCode;
        this.metadata.code = controlCode;
        this.metadata.id = ns.replace(/\_/g, '.') + "." + controlCode;
        let path = ns.replace(/\_/g, '.');
        this.metadata.at = path;
        // this.metadata.name = this.metadata.name || this.$questionBody;
        this.metadata.name = this.$questionBody;
        this.metadata_fullcode = key;
        this.metadata.level = 0;
        return { "key": this.metadata_fullcode, "md": this.metadata };
      } else {
        let index = this.metadata.id.lastIndexOf(".");
        let key = this.metadata.id.substring(0, index).replace(/\./g, "_") + "." + this.metadata.id.substr(index + 1);
        this.metadata_fullcode = key;
        this.metadata.level = 0;
        return { "key": this.metadata_fullcode, "md": this.metadata };
      }
    }
    return null;
  }

  addLogicMark(key, value, type) {
    // 如果关联数据发生变化时触发
    if (!this._logicMark[key]) {
      this._logicMark[key] = [];
    }
    if (this._logicMark[key].indexOf(value) < 0) {
      this._logicMark[key].push(value);
    }
    let keys = Object.keys(this._logicMark);
    //题目存在逻辑标记则隐藏
    if (keys.length > 0) {
      this.visible = false;
      this.element.attr("data-hidden", "");
    } else {
      this.visible = true;
      this.element.removeClass("hide").removeAttr("data-hidden");
    }
    if (!type) {
      if (this.root.logicExec) {
        this.root.logicExec(this);
      }
    }
  }

  removeLogicMark(key, value, type) {
    if (value == undefined) {
      delete this._logicMark[key];
    } else {
      if (this._logicMark[key]) {
        for (let i = this._logicMark[key].length - 1; i >= 0; i--) {
          if (this._logicMark[key][i] == value) {
            this._logicMark[key].splice(i, 1);
          }
        }
        if (this._logicMark[key].length <= 0) {
          delete this._logicMark[key];
        }
      }
    }
    let keys = Object.keys(this._logicMark);
    //题目存在逻辑标记则隐藏
    if (keys.length > 0) {
      this.visible = false;
      this.element.attr("data-hidden", "");
    } else {
      this.visible = true;
      this.element.removeAttr("data-hidden");
    }
    if (!type) {
      if (this.root.logicExec) {
        this.root.logicExec(this);
      }
    }

  }

  checkTrigHidden(data, _this) {
    //将逻辑处理交与QIPage整体统一执行
    if (this.root.logicExec) {
      this.root.logicExec(_this);
    }

  }

  getMissValue() {
    if (this.$metadata.valueAttributes.length <= 1) {
      return ""
    } else {
      let obj = {}
      for (let i = 0; i < this.$metadata.valueAttributes.length; i++) {
        let va = this.$metadata.valueAttributes[i];
        let code = va.code;
        obj[code] = "";
      }
      return obj;
    }
  }
}