// const dom = require("../../templates/Container.ejs");
import { Control } from './Control';
import { ControlEditor } from '../../editor/ControlEditor';
import { Question } from './Question';
import { ExamSubject } from './ExamSubject'
// import { HtmlElement } from './HtmlElement';

import { map } from '../../decorator/controlmap';

@map('布局基类', 'dsf.layoutcontrol', 'LayoutControl')
export class LayoutControl extends Control {
  constructor(id, isPart) {
    super(id, isPart);
    this.children = [];
    this._desingerClass = ControlEditor;
    this._isLayoutControl = true;
  }

  createElement() {
    let _this = this;
    super.createElement();
  }


  addChild(container, index, handler) {
    // console.time("添加")i+1
    container._parent = this;
    container.parentElement = handler || "#" + this.id;
    if (index === undefined && index === null) {
      this.children.push(container);
    } else {
      if (this.children[index]) {
        this.children.splice(index, 0, container);
      } else {
        this.children.push(container);
      }
    }

    let qIndex = 0;
    for (let i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
      if (this.isDesign) {
        if (this.children[i] instanceof Question || this.children[i] instanceof ExamSubject) {
          this.children[i].questionIndex = ++qIndex;
          // if ('$indexInExam' in this.children[i]) {
          //     this.children[i].indexInExam = qIndex;
          // }
        }
      }
    }
    if (this._root) {
      container._root = this._root;
      if (!container.$caption) {
        container.caption = container.ctrl_type + (++(container.root.$serial));
      }
    }
    container.render();
  }

  _addChild(container, index, handler) {
    container._parent = this;
    container.parentElement = handler || "#" + this.id;
    if (this._root) {
      container._root = this._root;
      if (!container.$caption) {
        container.caption = container.ctrl_type.toLowerCase() + (++(container.root.$serial));
      }
    }
    if (index === undefined && index === null) {
      this.children.push(container);
    } else {
      if (this.children[index]) {
        this.children.splice(index, 0, container);
      } else {
        this.children.push(container);
      }
    }

    let qIndex = 0;
    for (let i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
      if (this.children[i] instanceof Question || this.children[i] instanceof ExamSubject) {
        // this.children[i].questionIndex="Q"+(i+1);
        this.children[i].questionIndex = ++qIndex;
        // if ('$indexInExam' in this.children[i]) {
        //     this.children[i].indexInExam = qIndex;
        // }
      }
    }
  }

  renderChild() {
    for (var i = 0; i < this.children.length; i++) {
      this.children[i].root = this.root;
      this.children[i].parent = this;
      this.children[i].index = i;
      if (!this.children[i].caption) {
        this.children[i].caption = this.children[i].ctrl_type + (++(this.root.$serial));
      }
      // console.time("创建子节点"+this.children[i].id+"_"+this.children[i].ctrl_type)
      this.children[i].render();
      // console.timeEnd("创建子节点"+this.children[i].id+"_"+this.children[i].ctrl_type)
    }
  }
  renderReady() {
    super.renderReady();
  }
  render(el) {
    super.render(el);
  }
  remove() {
    this.emptyChild();
    super.remove();
  }
  removeChild(control, removeElement) {
    control._parent = null;
    let index = this.children.indexOf(control);
    if (index >= 0) {
      this.children.splice(index, 1);
      if (removeElement != false) {
        control.element.remove();
      }
    }
    for (var i = 0; i < this.children.length; i++) {
      this.children[i].index = i;
    }
  }
  emptyChild() {
    for (var i = this.children.length - 1; i >= 0; i--) {
      this.children[i].remove();
    }
  }
  resize() {
    super.resize();
    // let clearId=window.setTimeout(evt=>{

    // });
    // window.clearTimeout(clearId);
    if (this.children) {
      this.children.forEach(v => {
        v.resize();
      })
    }
  }

  ControlsForEach(callback, isSelf) {
    let result = true;
    if (isSelf != false) {
      result = callback(this);
    }
    if (result != false && this.children) {
      for (var i = 0; i < this.children.length; i++) {
        let c = this.children[i];
        if (c.ControlsForEach) {
          c.ControlsForEach(callback);
        } else {
          callback(c)
        }
      }
    }
  }
}