import {QsHelloMsg} from "../controls";
import {map} from  '../../../decorator/controlmap';

@map('问卷标题','dsf.qi.qstitle','QsTitle')
export class QsTitle extends QsHelloMsg{
  constructor(id, isPart) {
    super(id, isPart);
    this._noBorder = true;
    this.baseSetting = false;
  }

  renderContext() {
    super.renderContext();
    this._handlers.content.html("");
    this.$questionBody = this.$questionBody?this.$questionBody.replace('问卷标题',this._root.$title || '问卷标题'):this._root.$title;
    this._handlers.content.append(this.$questionBody);
  }

}
