function controlBaseSetting(settingHtmlPath,title,width,height){
    return function(target){
        target.prototype.baseSetting={
            settingHtmlPath:"/dsfa/pd/views/"+settingHtmlPath,
            title:title||"组件设置",
            width:width||"800px",
            height:height||"600px"
        }
    }
}
export {
    controlBaseSetting
}